class One_Click_Legal_Page_Manager_V9 {

    private $all_pages;
    private $option_name = 'oclg_options';
    private $options;

    public function __construct() {
        $this->setup_pages_array();
        $this->options = get_option($this->option_name, $this->get_default_options());
        add_action('admin_menu', array($this, 'add_plugin_page'));
        add_action('admin_post_oclg_action', array($this, 'handle_form_submission'));
        add_action('admin_init', array($this, 'register_settings'));
        add_action('admin_notices', array($this, 'show_admin_notices'));
        add_action('init', array($this, 'register_shortcodes'));
    }

    private function get_default_options() {
        return [
            'site_name'             => get_bloginfo('name'),
            'company_name'          => get_bloginfo('name'),
            'site_url'              => get_home_url(),
            'contact_email'         => get_option('admin_email'),
            'jurisdiction'          => 'the Netherlands',
            'policy_effective_date' => date('F j, Y'),
            'refund_days'           => '30',
            'review_period'         => '5',
            'refund_processing_time'=> '10',
            'auto_update_date'      => 1,
        ];
    }
    
    // --- All core plugin functions from V8.1 are preserved here ---
    // (The only change is in the get_all_templates() function)
    
    public function register_settings() { register_setting('oclg_settings_group', $this->option_name); }
    public function register_shortcodes() { foreach($this->get_default_options() as $key => $value) { add_shortcode($key, function() use ($key) { return esc_html($this->options[$key]); }); } }
    public function add_plugin_page() { add_menu_page('Legal Pages', 'Legal Pages', 'manage_options', 'one-click-legal-pages', array($this, 'admin_page_html'), 'dashicons-shield-alt', 80); }
    public function admin_page_html() { $active_tab = isset($_GET['tab']) ? sanitize_key($_GET['tab']) : 'generator'; ?> <div class="wrap"> <h1>One-Click Legal Page Manager</h1> <h2 class="nav-tab-wrapper"> <a href="?page=one-click-legal-pages&tab=generator" class="nav-tab <?php echo $active_tab == 'generator' ? 'nav-tab-active' : ''; ?>">Page Generator</a> <a href="?page=one-click-legal-pages&tab=settings" class="nav-tab <?php echo $active_tab == 'settings' ? 'nav-tab-active' : ''; ?>">Settings</a> <a href="?page=one-click-legal-pages&tab=advanced" class="nav-tab <?php echo $active_tab == 'advanced' ? 'nav-tab-active' : ''; ?>">Advanced Tools</a> </h2> <form method="post" action="admin-post.php"> <input type="hidden" name="action" value="oclg_action"> <?php if ($active_tab == 'generator') $this->render_generator_tab(); elseif ($active_tab == 'settings') $this->render_settings_tab(); else $this->render_advanced_tab(); ?> </form> <p style="margin-top: 30px; padding-top: 10px; border-top: 1px solid #ccc; font-style: italic;"> <strong>Disclaimer:</strong> The legal text generated by this plugin is a template and not a substitute for professional legal advice. Consult a qualified lawyer to ensure full compliance. </p> </div> <?php }
    private function render_generator_tab() { wp_nonce_field('oclg_generate_nonce', 'oclg_nonce'); ?> <input type="hidden" name="oclg_form_type" value="generate"> <h3>Generate Your Legal Pages</h3> <p>Select the pages you need. The content will be automatically populated with the information from your Settings tab. Pages that already exist will not be overwritten.</p> <?php $this->render_page_checkboxes(); ?> <?php submit_button('Generate Selected Pages', 'primary', 'submit', true, ['style' => 'margin-top:20px;']); ?> <?php }
    private function render_settings_tab() { wp_nonce_field('oclg_settings_nonce', 'oclg_nonce'); ?> <input type="hidden" name="oclg_form_type" value="save_settings"> <fieldset style="border: 1px solid #ccc; padding: 15px; margin-top: 20px; border-radius: 4px;"> <legend><strong>Business Information</strong></legend> <table class="form-table"> <tr><th scope="row"><label for="site_name">Website Name</label></th><td><input type="text" id="site_name" name="oclg_options[site_name]" value="<?php echo esc_attr($this->options['site_name']); ?>" required class="regular-text" /></td></tr> <tr><th scope="row"><label for="company_name">Company Name (Legal)</label></th><td><input type="text" id="company_name" name="oclg_options[company_name]" value="<?php echo esc_attr($this->options['company_name']); ?>" required class="regular-text" /></td></tr> <tr><th scope="row"><label for="site_url">Website URL</label></th><td><input type="url" id="site_url" name="oclg_options[site_url]" value="<?php echo esc_attr($this->options['site_url']); ?>" required class="regular-text" /></td></tr> <tr><th scope="row"><label for="contact_email">Public Contact Email</label></th><td><input type="email" id="contact_email" name="oclg_options[contact_email]" value="<?php echo esc_attr($this->options['contact_email']); ?>" required class="regular-text" /></td></tr> <tr><th scope="row"><label for="jurisdiction">Country/State of Jurisdiction</label></th><td><input type="text" id="jurisdiction" name="oclg_options[jurisdiction]" value="<?php echo esc_attr($this->options['jurisdiction']); ?>" class="regular-text" /></td></tr> </table> </fieldset> <fieldset style="border: 1px solid #ccc; padding: 15px; margin-top: 20px; border-radius: 4px;"> <legend><strong>Policy Date Settings</strong></legend> <table class="form-table"> <tr> <th scope="row"><label for="policy_effective_date">Policy Effective Date</label></th> <td> <input type="text" id="policy_effective_date" name="oclg_options[policy_effective_date]" value="<?php echo esc_attr($this->options['policy_effective_date']); ?>" required class="regular-text" /> <button type="button" class="button button-secondary" id="set_date_today">Set to Today</button> <p class="description">This date is used as the "last updated" date in your policies.</p> </td> </tr> <tr> <th scope="row">Date Automation</th> <td> <label> <input type="checkbox" name="oclg_options[auto_update_date]" value="1" <?php checked( !empty($this->options['auto_update_date']) ); ?>> Automatically update 'Policy Effective Date' to today when using the "Force Update Pages" tool. </label> </td> </tr> </table> </fieldset> <fieldset style="border: 1px solid #ccc; padding: 15px; margin-top: 20px; border-radius: 4px;"> <legend><strong>Refund Settings</strong></legend> <table class="form-table"> <tr><th scope="row"><label for="refund_days">Refund Period (Days)</label></th><td><input type="number" id="refund_days" name="oclg_options[refund_days]" value="<?php echo esc_attr($this->options['refund_days']); ?>" class="small-text" /></td></tr> <tr><th scope="row"><label for="review_period">Refund Review Period (Business Days)</label></th><td><input type="number" id="review_period" name="oclg_options[review_period]" value="<?php echo esc_attr($this->options['review_period']); ?>" class="small-text" /></td></tr> <tr><th scope="row"><label for="refund_processing_time">Refund Processing Time (Business Days)</label></th><td><input type="number" id="refund_processing_time" name="oclg_options[refund_processing_time]" value="<?php echo esc_attr($this->options['refund_processing_time']); ?>" class="small-text" /></td></tr> </table> </fieldset> <?php submit_button('Save All Settings'); ?> <script type="text/javascript"> document.addEventListener('DOMContentLoaded', function() { const dateField = document.getElementById('policy_effective_date'); const todayButton = document.getElementById('set_date_today'); if (dateField && todayButton) { todayButton.addEventListener('click', function() { const today = new Date(); const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"]; dateField.value = monthNames[today.getMonth()] + ' ' + today.getDate() + ', ' + today.getFullYear(); }); } }); </script> <?php }
    private function render_advanced_tab() { wp_nonce_field('oclg_advanced_nonce', 'oclg_nonce'); ?> <input type="hidden" name="oclg_form_type" value="advanced_tools"> <h3>Advanced Management Tools</h3> <table class="form-table"> <tr> <th scope="row">Force Update Pages</th> <td> <button type="submit" name="oclg_tool_action" value="force_update" class="button button-secondary" onclick="return confirm('This will overwrite the content of all pages previously created by this plugin with the latest templates and information from your settings. Are you sure?')">Force Update All Generated Pages</button> <p class="description">Use this if you have updated your settings and want to apply the changes to all existing pages this plugin created. This may also update the 'Policy Effective Date' if automation is enabled in Settings.</p> </td> </tr> <tr> <th scope="row">Create Legal Menu</th> <td> <button type="submit" name="oclg_tool_action" value="create_menu" class="button button-secondary">Create 'Legal' Menu</button> <p class="description">This will create a new menu named "Legal" containing links to all pages you've generated with this plugin. After creation, you must go to <strong>Appearance -> Menus -> Manage Locations</strong> to assign it to a theme location (e.g., "Footer Menu"). It will not create duplicate menus.</p> </td> </tr> </table> <h3>Shortcode Reference</h3> <p>You can use these shortcodes in your pages, posts, or widgets. The plugin will automatically replace them with the values from your settings.</p> <div style="display: flex; flex-wrap: wrap; gap: 10px; background: #fff; border: 1px solid #ccc; padding: 15px; border-radius: 4px;"> <?php foreach(array_keys($this->get_default_options()) as $key): ?> <code style="background: #f1f1f1; padding: 2px 6px; border-radius: 4px;">{{<?php echo esc_html($key); ?>}}</code> <?php endforeach; ?> </div> <?php }
    public function handle_form_submission() { if (!isset($_POST['oclg_nonce']) || !current_user_can('manage_options')) { wp_die('Security check failed!'); } $form_type = sanitize_text_field($_POST['oclg_form_type']); $nonce_action = ''; if ($form_type === 'generate') { $nonce_action = 'oclg_generate_nonce'; } elseif ($form_type === 'save_settings') { $nonce_action = 'oclg_settings_nonce'; } elseif ($form_type === 'advanced_tools') { $nonce_action = 'oclg_advanced_nonce'; } if (empty($nonce_action) || !wp_verify_nonce($_POST['oclg_nonce'], $nonce_action)) { wp_die('Nonce verification failed! This may be due to a page timeout. Please go back and try again.'); } $status = ''; $count = 0; if ($form_type === 'generate') list($status, $count) = $this->generate_pages_action(); if ($form_type === 'save_settings') $status = $this->save_settings_action(); if ($form_type === 'advanced_tools' && isset($_POST['oclg_tool_action'])) { $tool = sanitize_text_field($_POST['oclg_tool_action']); if ($tool === 'force_update') list($status, $count) = $this->force_update_action(); if ($tool === 'create_menu') $status = $this->create_menu_action(); } $redirect_url = add_query_arg('status', $status, wp_get_referer()); if ($count > 0) $redirect_url = add_query_arg('count', $count, $redirect_url); wp_safe_redirect($redirect_url); exit; }
    private function generate_pages_action() { if (empty($_POST['pages_to_generate'])) return ['error_selection', 0]; $selected_pages = array_map('sanitize_text_field', $_POST['pages_to_generate']); $count = 0; foreach ($selected_pages as $slug) { if (array_key_exists($slug, $this->all_pages) && !get_page_by_path($slug, OBJECT, 'page')) { $this->create_page($this->all_pages[$slug]['title'], $this->get_page_content($slug), $slug); $count++; } } return ['success_generated', $count]; }
    private function save_settings_action() { if (!isset($_POST['oclg_options'])) return 'error_general'; $posted_options = $_POST['oclg_options']; $clean_options = $this->options; foreach($this->get_default_options() as $key => $value) { if(isset($posted_options[$key])) { $clean_options[$key] = sanitize_text_field($posted_options[$key]); } } $clean_options['auto_update_date'] = isset($posted_options['auto_update_date']) ? 1 : 0; update_option($this->option_name, $clean_options); $this->options = $clean_options; return 'success_settings'; }
    private function force_update_action() { if (!empty($this->options['auto_update_date'])) { $this->options['policy_effective_date'] = date('F j, Y'); update_option($this->option_name, $this->options); } $args = ['post_type' => 'page', 'meta_key' => '_is_oclg_page', 'meta_value' => '1', 'posts_per_page' => -1]; $managed_pages = get_posts($args); $count = 0; foreach($managed_pages as $page) { $slug = $page->post_name; if(array_key_exists($slug, $this->all_pages)) { $this->create_page($this->all_pages[$slug]['title'], $this->get_page_content($slug), $slug, $page->ID); $count++; } } return ['success_updated', $count]; }
    private function create_menu_action() { $menu_name = 'Legal'; if (!wp_get_nav_menu_object($menu_name)) { $menu_id = wp_create_nav_menu($menu_name); $args = ['post_type' => 'page', 'meta_key' => '_is_oclg_page', 'meta_value' => '1', 'posts_per_page' => -1]; $managed_pages = get_posts($args); foreach($managed_pages as $page) { wp_update_nav_menu_item($menu_id, 0, ['menu-item-title' => esc_html($page->post_title), 'menu-item-object' => 'page', 'menu-item-object-id' => $page->ID, 'menu-item-type' => 'post_type', 'menu-item-status' => 'publish']); } return 'success_menu'; } return 'error_menu_exists'; }
    private function create_page($title, $content, $slug, $existing_id = 0) { $content = str_replace(['{{', '}}'], ['[', ']'], $content); $final_content = do_shortcode($content); $page_data = [ 'post_title'    => wp_strip_all_tags($title), 'post_content'  => $final_content, 'post_status'   => 'publish', 'post_author'   => get_current_user_id(), 'post_type'     => 'page', 'post_name'     => $slug, ]; if ($existing_id > 0) { $page_data['ID'] = $existing_id; wp_update_post($page_data); } else { $page_id = wp_insert_post($page_data); if($page_id && !is_wp_error($page_id)) { add_post_meta($page_id, '_is_oclg_page', '1', true); } } }
    private function get_page_content($slug) { $templates = $this->get_all_templates(); return isset($templates[$slug]) ? $templates[$slug] : '<p>Content for this page is not available.</p>'; }
    private function render_page_checkboxes() { echo '<div style="display: flex; flex-wrap: wrap; gap: 20px;">'; $groups = []; foreach ($this->all_pages as $slug => $page) { $groups[$page['group']][] = ['slug' => $slug, 'title' => $page['title']]; } foreach ($groups as $group_name => $pages) { echo '<fieldset style="border: 1px solid #ccc; padding: 15px; min-width: 300px; border-radius: 4px;"><legend><strong>' . esc_html($group_name) . '</strong></legend>'; foreach ($pages as $page) { printf('<label><input type="checkbox" name="pages_to_generate[]" value="%s" checked> %s</label><br>', esc_attr($page['slug']), esc_html($page['title'])); } echo '</fieldset>'; } echo '</div>'; }
    public function show_admin_notices() { if(!isset($_GET['status'])) return; $status = sanitize_key($_GET['status']); $count = isset($_GET['count']) ? intval($_GET['count']) : 0; $messages = [ 'success_generated' => "Success! {$count} pages created.", 'success_updated'   => "Success! {$count} pages have been updated with your latest settings.", 'success_settings'  => "Settings saved successfully.", 'success_menu'      => "Menu 'Legal' was created successfully. Go to Appearance -> Menus to assign it.", 'error_selection'   => "Error: No pages selected.", 'error_menu_exists' => "Notice: A menu named 'Legal' already exists. No new menu was created.", 'error_general'     => "An unknown error occurred." ]; if(isset($messages[$status])) { $type = strpos($status, 'error') === 0 ? 'error' : 'success'; echo "<div class='notice notice-{$type} is-dismissible'><p>{$messages[$status]}</p></div>"; } }
    private function setup_pages_array() { $this->all_pages = [ 'privacy-policy' => ['title' => 'Privacy Policy', 'group' => 'Core Policies'], 'eu-privacy-policy' => ['title' => 'EU Privacy Policy (GDPR)', 'group' => 'Core Policies'], 'terms-of-use' => ['title' => 'Terms of Use', 'group' => 'Core Policies'], 'disclaimer' => ['title' => 'Disclaimer', 'group' => 'Core Policies'], 'about-us' => ['title' => 'About Us', 'group' => 'Core Policies'], 'refund-policy' => ['title' => 'Refund Policy', 'group' => 'Financial Policies'], 'digital-goods-refund-policy' => ['title' => 'Digital Goods Refund Policy', 'group' => 'Financial Policies'], 'earnings-disclaimer' => ['title' => 'Earnings Disclaimer', 'group' => 'Financial Policies'], 'affiliate-disclosure' => ['title' => 'Affiliate Disclosure', 'group' => 'Disclosure Policies'], 'advertising-disclosures' => ['title' => 'Advertising Disclosures', 'group' => 'Disclosure Policies'], 'confidentiality-disclosure' => ['title' => 'Confidentiality Disclosure', 'group' => 'Disclosure Policies'], 'testimonials-disclosure' => ['title' => 'Testimonials Disclosure', 'group' => 'Disclosure Policies'], 'medical-disclaimer' => ['title' => 'Medical Disclaimer', 'group' => 'Disclosure Policies'], 'affiliate-agreement' => ['title' => 'Affiliate Agreement', 'group' => 'Disclosure Policies'], 'amazon-affiliate' => ['title' => 'Amazon Affiliate Disclosure', 'group' => 'Disclosure Policies'], 'cookie-policy' => ['title' => 'Cookie Privacy Policy', 'group' => 'Technology Policies'], 'facebook-policy' => ['title' => 'Facebook Policy', 'group' => 'Technology Policies'], 'linking-policy' => ['title' => 'Linking Policy', 'group' => 'Technology Policies'], 'external-links-policy' => ['title' => 'External Links Policy', 'group' => 'Technology Policies'], 'antispam-policy' => ['title' => 'Antispam Policy', 'group' => 'Technology Policies'], 'double-dart-cookie' => ['title' => 'Double Dart Cookie', 'group' => 'Technology Policies'], 'eula' => ['title' => 'End-User License Agreement (EULA)', 'group' => 'Technology Policies'], 'coppa-policy' => ['title' => 'COPPA – Children’s Online Privacy Policy', 'group' => 'Compliance Policies'], 'dmca' => ['title' => 'DMCA Policy', 'group' => 'Compliance Policies'], 'forced-agreement' => ['title' => 'Forced Agreement to the Terms', 'group' => 'Compliance Policies'], 'ccpa' => ['title' => 'California Privacy Rights (CCPA)', 'group' => 'Compliance Policies'], ]; }

