            'refund-policy' => '<h2>Refund Policy</h2><p>{{site_name}} aims to provide customer satisfaction. If you\'re not happy with your purchase, you may request a refund within {{refund_days}} days.</p><p>Refunds will only be processed if the product is defective, not as described, or fails to function as intended.</p><p>To initiate a refund, contact us at {{contact_email}} with proof of purchase and a detailed explanation.</p><p>Refund requests will be reviewed within {{review_period}} business days.</p><p>Approved refunds will be issued to the original payment method within {{refund_processing_time}} business days.</p><p>This policy is subject to change and does not affect your statutory rights under applicable law.</p><p>For more details, visit our full terms at {{site_url}}/terms-of-use.</p>',
            'digital-goods-refund-policy' => '<h2>Digital Goods Refund Policy</h2><p>Due to the nature of digital content, we do not offer refunds once a product has been downloaded or accessed, unless defective.</p><p>All digital sales on {{site_name}} are final unless otherwise noted on the product page.</p><p>Exceptions may apply under special circumstances, such as technical failure or duplicate transactions.</p><p>Refund requests should be directed to {{contact_email}} within {{refund_days}} days of purchase.</p>',
            'linking-policy' => '<h2>Linking Policy</h2><p>You may link to content on {{site_name}} provided the link is not misleading, defamatory, or used in a false context.</p><p>We reserve the right to revoke linking permission at any time without notice.</p><p>Links must not imply endorsement unless explicitly approved by {{site_name}}.</p>',
            'external-links-policy' => '<h2>External Links Policy</h2><p>{{site_name}} may link to external websites. These links are provided for informational purposes only.</p><p>We are not responsible for the content, accuracy, or privacy practices of third-party websites.</p><p>Clicking on an external link means you are subject to the terms and privacy policies of that site.</p>',
            'cookie-policy' => '<h2>Cookie Privacy Policy</h2><p>{{site_name}} uses cookies to improve user experience, analyze traffic, and serve relevant ads.</p><p>By using our site, you consent to the use of cookies in accordance with this policy.</p><p>You may disable cookies in your browser settings at any time.</p><p>For more details, visit our full Cookie Policy page.</p>',
            'coppa-policy' => '<h2>Children’s Online Privacy Protection Act (COPPA)</h2><p>{{site_name}} does not knowingly collect or solicit personal information from children under the age of 13.</p><p>If you are under 13, do not use this site or submit any personal information.</p><p>If we learn that we have collected personal information from a child under 13, we will delete that information promptly.</p><p>Parents or guardians may contact us at {{contact_email}} to review or request deletion of a child’s information.</p><p>We recommend parents monitor their children’s internet activity and guide them regarding safe online practices.</p>',
            'advertising-disclosures' => '<h2>Advertising Disclosures</h2><p>{{site_name}} may display advertisements, including third-party and affiliate links.</p><p>We may receive compensation for clicks, views, or purchases made through these links.</p><p>Sponsored content will always be clearly marked as such.</p><p>We only promote products/services we believe offer value to our users.</p>',
            'confidentiality-disclosure' => '<h2>Confidentiality Disclosure</h2><p>All sensitive or confidential information shared with {{site_name}} is treated with strict confidentiality.</p><p>We will not disclose your private information to any third party unless legally required.</p><p>Your trust is important to us, and we take data confidentiality seriously.</p>',
            'testimonials-disclosure' => '<h2>Testimonials Disclosure</h2><p>Testimonials featured on {{site_name}} are from real users reflecting their opinions and experiences.</p><p>However, individual results may vary and are not guaranteed.</p><p>Some testimonials may have been received in exchange for free products or services.</p>',
            'affiliate-disclosure' => '<h2>Affiliate Disclosure</h2><p>{{site_name}} may include affiliate links to products and services.</p><p>We may earn a commission for purchases made through these links, at no extra cost to you.</p><p>This helps support our operations and content creation.</p><p>We only recommend products we trust and use ourselves.</p>',
            'disclaimer' => '<h2>Disclaimer</h2><p>The content on {{site_name}} is provided for general informational purposes only.</p><p>We make no warranties about the completeness, reliability, or accuracy of this information.</p><p>Any action you take based on this information is strictly at your own risk.</p>',
            'earnings-disclaimer' => '<h2>Earnings Disclaimer</h2><p>Any earnings or income statements on {{site_name}} are estimates only.</p><p>There is no guarantee that you will achieve similar results.</p><p>Your level of success depends on your experience, skills, and effort.</p>',
            'medical-disclaimer' => '<h2>Medical Disclaimer</h2><p>Content on {{site_name}} is not a substitute for professional medical advice, diagnosis, or treatment.</p><p>Always seek the advice of your physician or another qualified health provider for any medical condition.</p>',
            'terms-of-use' => '<h2>Terms of Use</h2><p>By accessing {{site_name}}, you agree to comply with and be bound by these terms and all applicable laws.</p><p>You agree not to misuse the site or its content in any way.</p>',
            'forced-agreement' => '<h2>Forced Agreement</h2><p>Continued use of {{site_name}} implies acceptance of our terms, policies, and disclaimers.</p><p>If you disagree with any part of these terms, please discontinue use of the site.</p>',
            'affiliate-agreement' => '<h2>Affiliate Agreement</h2><p>Affiliates must comply with all applicable laws, including FTC guidelines.</p><p>Affiliates may not engage in misleading advertising or spam.</p>',
            'amazon-affiliate' => '<h2>Amazon Affiliate Disclosure</h2><p>{{site_name}} is a participant in the Amazon Services LLC Associates Program.</p><p>We earn fees by linking to Amazon.com and affiliated sites.</p>',
            'dmca' => '<h2>DMCA Policy</h2><p>If you believe your copyright-protected work was posted on {{site_name}} without permission, contact us at {{contact_email}}.</p><p>We comply with the Digital Millennium Copyright Act (DMCA) and will act accordingly.</p>',
            'antispam-policy' => '<h2>Antispam Policy</h2><p>{{site_name}} has a strict zero-tolerance policy toward spam.</p><p>We do not send unsolicited emails and you can unsubscribe anytime using the link provided.</p>',
            'double-dart-cookie' => '<h2>Double Dart Cookie</h2><p>Third-party vendors, including Google, use cookies to serve ads based on prior visits to our site.</p><p>Users may opt out of personalized advertising by visiting Ads Settings.</p>',
            'about-us' => '<h2>About Us</h2><p>Welcome to {{site_name}}. We are committed to providing quality content and services for our users.</p><p>Contact us at {{contact_email}} for inquiries, support, or suggestions.</p>',
            'ccpa' => '<h2>California Privacy Rights (CCPA)</h2><p>California residents may request access to, correction, or deletion of their personal data.</p><p>To make a request, contact us at {{contact_email}} with “California Privacy Rights” in the subject line.</p>',
            'eula' => '<h2>End-user License Agreement (EULA)</h2><p>By installing or using {{site_name}}\'s software, you agree to the terms of this license.</p><p>You may not redistribute, modify, or reverse-engineer the software without permission.</p>',
        ];

        foreach($original_templates as $slug => $text) {
            $image_url = esc_url($image_base_url . $slug . '.png');
            $image_html = '<img src="' . $image_url . '" alt="' . esc_attr($this->all_pages[$slug]['title']) . '" style="max-width:100%; height:auto; margin-bottom: 20px; border-radius: 8px;" />';
            $templates[$slug] = $image_html . $text;
        }

        return $templates;
    }
}

